mapper.select:
select Teacher_ID as teacherId, Teacher_Name as teacherName, Teacher_Department as teacherDepartment, Teacher_Title as teacherTitle, Teacher_Status as teacherStatus from teacher
and Teacher_Name like concat('%', #{teacherName}, '%')
and Teacher_Department = #{teacherDepartment}
order by Teacher_ID limit #{offset}, #{pageSize}

select count(*) from teacher
and Teacher_Name like concat('%', #{teacherName}, '%')
and Teacher_Department = #{teacherDepartment}
